practices.bad:
class OrderService {
    let network = NetworkManager()
    func fetchOrders() { network.get("/orders") }
}

practices.good:
protocol NetworkClient {
    func get(_ path: String) async throws -> Data
}
class OrderService {
    let network: NetworkClient
    init(network: NetworkClient) { self.network = network }
}

practices.bad:
class ProfileVC: UIViewController, UITableViewDelegate, UITableViewDataSource {
    // all delegate methods mixed with view logic
}

practices.good:
class ProfileVC: UIViewController { ... }
extension ProfileVC: UITableViewDelegate { ... }
extension ProfileVC: UITableViewDataSource { ... }

// MARK: - Properties
// MARK: - Lifecycle
// MARK: - Actions
// MARK: - Private Helpers

practices.bad:
func fetchUser() -> User? {
    // returns nil on error — caller can't distinguish "not found" from "network error"
}

practices.good:
func fetchUser() async throws -> User {
    // throws specific errors the caller can handle
}
// or: func fetchUser() -> Result<User, FetchError>

practices.bad:
func loadData() async {
    let data = try! await fetchData()
}

practices.good:
func loadData() async {
    do {
        let data = try await fetchData()
        display(data)
    } catch {
        showError(error)
    }
}

practices.bad:
let formatter: DateFormatter = {
    let f = DateFormatter()
    f.dateFormat = "yyyy-MM-dd"
    return f
}()

practices.good:
lazy var formatter: DateFormatter = {
    let f = DateFormatter()
    f.dateFormat = "yyyy-MM-dd"
    return f
}()

practices.bad:
func processImage(_ image: UIImage) {
    let filtered = applyHeavyFilter(image) // blocks main thread
    imageView.image = filtered
}

practices.good:
func processImage(_ image: UIImage) {
    DispatchQueue.global(qos: .userInitiated).async {
        let filtered = applyHeavyFilter(image)
        DispatchQueue.main.async {
            self.imageView.image = filtered
        }
    }
}

practices.bad:
func tableView(_ tv: UITableView, cellForRowAt ip: IndexPath) -> UITableViewCell {
    let formatter = DateFormatter()
    formatter.dateFormat = "yyyy-MM-dd"
    cell.label.text = formatter.string(from: item.date)
}

practices.good:
private lazy var dateFormatter: DateFormatter = {
    let f = DateFormatter()
    f.dateFormat = "yyyy-MM-dd"
    return f
}()
func tableView(_ tv: UITableView, cellForRowAt ip: IndexPath) -> UITableViewCell {
    cell.label.text = dateFormatter.string(from: item.date)
}
